dashboard.definition:
{
  "title": "Source - Webex API",
  "description": "Cisco Webex REST API — device quality monitoring, ghost meeting detection, admin audit and cross-sourcetype correlation",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Webex API Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") by _time span=1h"
      }
    },
    "ds_total_meetings": {
      "type": "ds.search",
      "name": "Total Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings\" | stats count"
      }
    },
    "ds_admin_actions": {
      "type": "ds.search",
      "name": "Admin Actions",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\") | stats count"
      }
    },
    "ds_ghost_meetings": {
      "type": "ds.search",
      "name": "Ghost Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings\" state=\"missed\" | stats count"
      }
    },
    "ds_device_quality_count": {
      "type": "ds.search",
      "name": "Device Quality Records",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meeting:qualities\" clientType=\"Telepresence\" | stats dc(meetingInstanceId) as count"
      }
    },
    "ds_unique_actors": {
      "type": "ds.search",
      "name": "Unique Actors",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\") | eval user=coalesce(hostEmail, actorEmail, user) | where isnotnull(user) | stats dc(user) as count"
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Events Over Time by Sourcetype",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:cisco:webex:meetings\" OR sourcetype=\"FAKE:cisco:webex:admin:audit:events\" OR sourcetype=\"FAKE:cisco:webex:security:audit:events\" OR sourcetype=\"FAKE:cisco:webex:meeting:qualities\" OR sourcetype=\"FAKE:cisco:webex:call:detailed_history\") | eval st=replace(sourcetype,\"FAKE:cisco:webex:\",\"\") | timechart span=1h count by st"
      }
    },
    "ds_meeting_state": {
      "type": "ds.search",
      "name": "Meeting State Distribution",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings\" | stats count by state | rename state as \"State\""
      }
    },
    "ds_hw_quality": {
      "type": "ds.search",
      "name": "Hardware Type Quality",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meeting:qualities\" clientType=\"Telepresence\" | stats dc(meetingInstanceId) as Meetings, avg(joinMeetingTime) as avg_join, count as \"Quality Records\" by hardwareType, webexUserName | eval \"Avg Join (s)\"=round(avg_join,1) | sort -Meetings | fields hardwareType, webexUserName, Meetings, \"Avg Join (s)\", \"Quality Records\" | rename hardwareType as \"Hardware Type\", webexUserName as \"Device Name\""
      }
    },
    "ds_hw_summary": {
      "type": "ds.search",
      "name": "Hardware Type Summary",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meeting:qualities\" clientType=\"Telepresence\" | stats dc(meetingInstanceId) as Meetings, avg(joinMeetingTime) as avg_join by hardwareType | eval avg_join=round(avg_join,1) | sort -Meetings | rename hardwareType as \"Hardware Type\", avg_join as \"Avg Join (s)\""
      }
    },
    "ds_ghost_over_time": {
      "type": "ds.search",
      "name": "Ghost vs Active Meetings Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings\" | eval status=if(state=\"missed\",\"Ghost (missed)\",\"Active (ended)\") | timechart span=1d count by status"
      }
    },
    "ds_top_actors": {
      "type": "ds.search",
      "name": "Top Meeting Hosts",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings\" state=\"ended\" | stats count by hostDisplayName | sort -count | head 15 | rename hostDisplayName as \"Host\", count as \"Meetings\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings\" | table _time title state hostDisplayName meetingNumber id | sort -_time | head 30 | rename title as \"Title\", state as \"State\", hostDisplayName as \"Host\", meetingNumber as \"Meeting Number\", id as \"Meeting ID\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Webex API (REST)\n\n**Sourcetypes:** `meetings`, `meeting:qualities`, `admin:audit:events`, `security:audit:events`, `call:detailed_history` | **Device Quality:** 21 Telepresence endpoints\n\n**Cross-correlation:** `id` / `meetingNumber` shared with Webex TA (`confID` / `meetingKey`) — `meetingInstanceId` in quality records links to `id` in meetings.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Events",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_meetings": {
      "type": "splunk.singlevalue",
      "title": "Total Meetings",
      "dataSources": { "primary": "ds_total_meetings" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_admin_actions": {
      "type": "splunk.singlevalue",
      "title": "Admin/Security",
      "dataSources": { "primary": "ds_admin_actions" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_ghost": {
      "type": "splunk.singlevalue",
      "title": "Ghost Meetings",
      "dataSources": { "primary": "ds_ghost_meetings" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_devices": {
      "type": "splunk.singlevalue",
      "title": "Device Sessions",
      "dataSources": { "primary": "ds_device_quality_count" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#2ED6BB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_actors": {
      "type": "splunk.singlevalue",
      "title": "Unique Actors",
      "dataSources": { "primary": "ds_unique_actors" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Events Over Time by Sourcetype",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_meeting_state": {
      "type": "splunk.pie",
      "title": "Meeting State",
      "dataSources": { "primary": "ds_meeting_state" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#53A051", "#DC4E41"],
        "seriesColorsByField": {
          "ended": "#53A051",
          "missed": "#DC4E41"
        }
      }
    },
    "viz_ghost_over_time": {
      "type": "splunk.column",
      "title": "Ghost vs Active Meetings (Daily)",
      "dataSources": { "primary": "ds_ghost_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Meetings / day",
        "yAxisTitleVisibility": "show",
        "seriesColors": ["#53A051", "#DC4E41"],
        "seriesColorsByField": {
          "Active (ended)": "#53A051",
          "Ghost (missed)": "#DC4E41"
        }
      },
      "showProgressBar": true
    },
    "viz_hw_summary": {
      "type": "splunk.bar",
      "title": "Meetings by Hardware Type",
      "dataSources": { "primary": "ds_hw_summary" },
      "options": {
        "seriesColors": ["#2ED6BB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Meetings",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_hw_quality": {
      "type": "splunk.table",
      "title": "Room Device Quality Details",
      "dataSources": { "primary": "ds_hw_quality" },
      "options": {
        "count": 21,
        "showRowNumbers": false
      },
      "showProgressBar": true
    },
    "viz_top_actors": {
      "type": "splunk.bar",
      "title": "Top Meeting Hosts",
      "dataSources": { "primary": "ds_top_actors" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Meetings",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Meetings",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Meetings",
      "dataSources": { "primary": "ds_sample_events" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 200, "h": 120 } },
      { "item": "viz_kpi_meetings", "type": "block", "position": { "x": 200, "y": 150, "w": 200, "h": 120 } },
      { "item": "viz_kpi_admin_actions", "type": "block", "position": { "x": 400, "y": 150, "w": 200, "h": 120 } },
      { "item": "viz_kpi_ghost", "type": "block", "position": { "x": 600, "y": 150, "w": 200, "h": 120 } },
      { "item": "viz_kpi_devices", "type": "block", "position": { "x": 800, "y": 150, "w": 200, "h": 120 } },
      { "item": "viz_kpi_actors", "type": "block", "position": { "x": 1000, "y": 150, "w": 200, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 600, "h": 300 } },
      { "item": "viz_ghost_over_time", "type": "block", "position": { "x": 600, "y": 270, "w": 600, "h": 300 } },
      { "item": "viz_hw_summary", "type": "block", "position": { "x": 0, "y": 570, "w": 600, "h": 300 } },
      { "item": "viz_meeting_state", "type": "block", "position": { "x": 600, "y": 570, "w": 250, "h": 300 } },
      { "item": "viz_top_actors", "type": "block", "position": { "x": 850, "y": 570, "w": 350, "h": 300 } },
      { "item": "viz_hw_quality", "type": "block", "position": { "x": 0, "y": 870, "w": 1200, "h": 400 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 1270, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 1320, "w": 1200, "h": 400 } }
    ]
  }
}
